// Normaliza el payload que llega del Telegram Trigger
const msg = $input.first().json.message || {};
const chat_id = msg.chat ? msg.chat.id : null;
const telegram_user = msg.from ? msg.from.id : chat_id;
const text = (msg.text || '').trim();

if (!chat_id) {
  // Ignora updates que no sean mensajes de texto (ej. stickers, ediciones)
  return [];
}

return [{
  json: { chat_id, telegram_user, text }
}];

// ============================================================
// MOTOR DE ESTADO - Bot de Tutorías (Telegram + Google Sheets)
// Lee: SESSIONS, ESTUDIANTES, TUTORES, DISPONIBILIDAD, TUTORIAS, Materias
// Devuelve: mensaje a enviar + acción a ejecutar sobre Sheets + nuevo estado de sesión
// ============================================================

function get(nodeName) {
  try { return $items(nodeName).map(i => i.json); } catch (e) { return []; }
}

const input = $input.first().json; // { chat_id, telegram_user, text }

const sessions = get('Leer SESSIONS');
const estudiantes = get('Leer ESTUDIANTES');
const tutores = get('Leer TUTORES');
const disponibilidad = get('Leer DISPONIBILIDAD');
const tutorias = get('Leer TUTORIAS');
const materiasRow = get('Leer Materias')[0] || {};
const materiasList = Object.values(materiasRow).filter(v => v && String(v).trim() !== '');

const telegram_user = String(input.telegram_user);
const chat_id = input.chat_id;
const text = (input.text || '').trim();

let session = sessions.find(s => String(s.telegram_user) === telegram_user);
let pantalla = session ? session.pantalla_actual : 'inicio';
let paso = session ? (Number(session.paso_actual) || 0) : 0;
let datos = {};
try { datos = session && session.datos_parciales ? JSON.parse(session.datos_parciales) : {}; } catch (e) { datos = {}; }

let estudiante = estudiantes.find(e => String(e.telegram_user) === telegram_user);

let respuesta = '';
let accion = 'NONE';
let accion_datos = {};
let nueva_pantalla = pantalla;
let nuevo_paso = paso;
let nuevos_datos = datos;

const MENU_TEXT = "👋 ¡Hola! ¿Qué deseas hacer?\n1️⃣ Registrarme\n2️⃣ Agendar tutoría\n3️⃣ Consultar mis tutorías\n4️⃣ Cancelar tutoría\n\nEscribe el número de la opción.";

function irAMenu(msgPrevio) {
  nueva_pantalla = 'inicio';
  nuevo_paso = 0;
  nuevos_datos = {};
  respuesta = (msgPrevio ? msgPrevio + "\n\n" : '') + MENU_TEXT;
}

if (/^\/start$/i.test(text) || /^menu$/i.test(text)) {
  irAMenu();
} else {
  switch (pantalla) {

    case 'inicio': {
      if (text === '1') {
        if (estudiante) {
          irAMenu('Ya estás registrado como ' + estudiante.nombre + '.');
        } else {
          nueva_pantalla = 'registro_nombre';
          nuevo_paso = 1;
          nuevos_datos = {};
          respuesta = '✏️ ¿Cuál es tu nombre completo?';
        }
      } else if (text === '2') {
        if (!estudiante) {
          respuesta = '⚠️ Primero debes registrarte (opción 1) antes de agendar una tutoría.\n\n' + MENU_TEXT;
        } else if (materiasList.length === 0) {
          respuesta = '⚠️ No hay materias configuradas actualmente. Intenta más tarde.\n\n' + MENU_TEXT;
        } else {
          const lista = materiasList.map((m, i) => (i + 1) + '️⃣ ' + m).join('\n');
          nueva_pantalla = 'agendar_materia';
          nuevo_paso = 1;
          nuevos_datos = {};
          respuesta = '📚 ¿Qué materia necesitas?\n' + lista;
        }
      } else if (text === '3') {
        if (!estudiante) {
          respuesta = '⚠️ Primero debes registrarte (opción 1).\n\n' + MENU_TEXT;
        } else {
          const propias = tutorias.filter(t => t.id_estudiante === estudiante.id_estudiante && t.estado !== 'Cancelada');
          if (propias.length === 0) {
            respuesta = '📭 No tienes tutorías agendadas.\n\n' + MENU_TEXT;
          } else {
            const lista = propias.map(t => `• ${t.materia} - ${t.fecha} ${t.hora} (${t.estado})`).join('\n');
            respuesta = '📋 Tus tutorías:\n' + lista + '\n\n' + MENU_TEXT;
          }
          nueva_pantalla = 'inicio'; nuevo_paso = 0; nuevos_datos = {};
        }
      } else if (text === '4') {
        if (!estudiante) {
          respuesta = '⚠️ Primero debes registrarte (opción 1).\n\n' + MENU_TEXT;
        } else {
          const cancelables = tutorias.filter(t => t.id_estudiante === estudiante.id_estudiante && t.estado === 'Confirmada');
          if (cancelables.length === 0) {
            respuesta = '📭 No tienes tutorías activas para cancelar.\n\n' + MENU_TEXT;
            nueva_pantalla = 'inicio'; nuevo_paso = 0; nuevos_datos = {};
          } else {
            const lista = cancelables.map((t, i) => `${i + 1}️⃣ ${t.materia} - ${t.fecha} ${t.hora}`).join('\n');
            nueva_pantalla = 'cancelar_seleccionar';
            nuevo_paso = 1;
            nuevos_datos = { candidatas: cancelables.map(t => t.id_tutoria) };
            respuesta = '❌ ¿Cuál tutoría deseas cancelar?\n' + lista;
          }
        }
      } else {
        irAMenu('No entendí esa opción.');
      }
      break;
    }

    case 'registro_nombre': {
      if (!text) { respuesta = '✏️ Por favor escribe tu nombre completo.'; break; }
      nuevos_datos = { nombre: text };
      nueva_pantalla = 'registro_materias';
      nuevo_paso = 2;
      respuesta = '📚 ¿Qué materias te interesan? (sepáralas por comas)\nEj: ' + materiasList.slice(0, 2).join(', ');
      break;
    }

    case 'registro_materias': {
      if (!text) { respuesta = '📚 Por favor escribe al menos una materia.'; break; }
      const elegidas = text.split(',').map(m => m.trim()).filter(Boolean);
      const validas = elegidas.filter(m => materiasList.some(ml => ml.toLowerCase() === m.toLowerCase()));
      if (validas.length === 0) {
        respuesta = '⚠️ No reconocí esas materias. Materias disponibles: ' + materiasList.join(', ');
        break;
      }
      const id_estudiante = 'EST' + Date.now();
      accion = 'REGISTRAR_ESTUDIANTE';
      accion_datos = {
        id_estudiante,
        telegram_user,
        nombre: datos.nombre,
        materias_interes: validas.join(',')
      };
      irAMenu('✅ ¡Listo, ' + datos.nombre + '! Quedaste registrado.');
      break;
    }

    case 'agendar_materia': {
      const idx = parseInt(text, 10) - 1;
      if (isNaN(idx) || idx < 0 || idx >= materiasList.length) {
        respuesta = '⚠️ Elige un número válido de la lista.';
        break;
      }
      const materia = materiasList[idx];
      const tutoresAptos = tutores.filter(t => t.estado === 'Activo' &&
        String(t.especialidad_materias || '').split(',').map(s => s.trim().toLowerCase()).includes(materia.toLowerCase()));
      const idsAptos = tutoresAptos.map(t => t.id_tutor);
      const opcionesDisp = disponibilidad.filter(d => d.estado === 'Libre' && idsAptos.includes(d.id_tutor));
      if (opcionesDisp.length === 0) {
        irAMenu('😕 No hay tutores disponibles para ' + materia + ' en este momento.');
        break;
      }
      const opciones = opcionesDisp.map(d => {
        const tut = tutoresAptos.find(t => t.id_tutor === d.id_tutor);
        return { id_dispo: d.id_dispo, id_tutor: d.id_tutor, nombre_tutor: tut ? tut.nombre : d.id_tutor, dia_semana: d.dia_semana, hora_inicio: d.hora_inicio, hora_fin: d.hora_fin };
      });
      const lista = opciones.map((o, i) => `${i + 1}️⃣ ${o.nombre_tutor} - ${o.dia_semana} ${o.hora_inicio}-${o.hora_fin}`).join('\n');
      nueva_pantalla = 'agendar_confirmar';
      nuevo_paso = 2;
      nuevos_datos = { materia, opciones: JSON.stringify(opciones) };
      respuesta = '🗓️ Horarios disponibles para ' + materia + ':\n' + lista + '\n\nElige un número.';
      break;
    }

    case 'agendar_confirmar': {
      let opciones = [];
      try { opciones = JSON.parse(datos.opciones || '[]'); } catch (e) { opciones = []; }
      const idx = parseInt(text, 10) - 1;
      if (isNaN(idx) || idx < 0 || idx >= opciones.length) {
        respuesta = '⚠️ Elige un número válido de la lista.';
        break;
      }
      const elegido = opciones[idx];
      const id_tutoria = 'TUTORIA' + Date.now();
      accion = 'CREAR_TUTORIA';
      accion_datos = {
        tutoria: {
          id_tutoria,
          id_estudiante: estudiante.id_estudiante,
          id_tutor: elegido.id_tutor,
          materia: datos.materia,
          fecha: elegido.dia_semana,
          hora: elegido.hora_inicio + '-' + elegido.hora_fin,
          estado: 'Confirmada',
          timestamp_creacion: new Date().toISOString()
        },
        id_dispo: elegido.id_dispo,
        id_tutoria_asociada: id_tutoria
      };
      irAMenu('✅ Tutoría de ' + datos.materia + ' agendada con ' + elegido.nombre_tutor + ' (' + elegido.dia_semana + ' ' + elegido.hora_inicio + '-' + elegido.hora_fin + ').');
      break;
    }

    case 'cancelar_seleccionar': {
      const candidatas = datos.candidatas || [];
      const idx = parseInt(text, 10) - 1;
      if (isNaN(idx) || idx < 0 || idx >= candidatas.length) {
        respuesta = '⚠️ Elige un número válido.';
        break;
      }
      const id_tutoria = candidatas[idx];
      const tutoriaObj = tutorias.find(t => t.id_tutoria === id_tutoria);
      accion = 'CANCELAR_TUTORIA';
      accion_datos = {
        id_tutoria,
        id_tutor: tutoriaObj ? tutoriaObj.id_tutor : null
      };
      irAMenu('✅ Tutoría cancelada correctamente.');
      break;
    }

    default: {
      irAMenu('Reiniciemos.');
    }
  }
}

if (!respuesta) { respuesta = MENU_TEXT; }

return [{
  json: {
    chat_id,
    telegram_user,
    mensaje_respuesta: respuesta,
    accion,
    accion_datos,
    session_update: {
      telegram_user,
      pantalla_actual: nueva_pantalla,
      paso_actual: nuevo_paso,
      datos_parciales: JSON.stringify(nuevos_datos)
    }
  }
}];
